SELECT t1.* FROM giv.inventory_snapshot t1 LEFT JOIN (SELECT a.material_code, a.logical_plant_id, a.action, a.deviate FROM giv.inventory_alert a WHERE ( SELECT count(id) FROM giv.inventory_alert b WHERE b.material_code = a.material_code AND b.logical_plant_id = a.logical_plant_id AND b.alert_date > a.alert_date )=0 AND deleted = 0) t2 ON t1.material_code = t2.material_code and t1.logical_plant_id = t2.logical_plant_id WHERE t1.tenant_id = #{tenantId} AND t1.deleted = 0 AND t1.logical_plant_id = #{logicalPlantId} AND t1.logical_plant_type = #{logicalPlantType} AND t1.material_code LIKE concat('%',concat('/', #{materialCode},'%')) ESCAPE '/'
AND t1.material_category_code LIKE concat('%',concat('/', #{materialCategoryCode},'%')) ESCAPE '/'
AND t1.warehouse_id = #{warehouseId}

